CREATE TABLE passports (id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),asset_id uuid NOT NULL REFERENCES assets(id),owner_customer_id uuid NOT NULL REFERENCES customers(id),status text NOT NULL CHECK(status IN('active','archived')),created_at timestamptz NOT NULL,UNIQUE(tenant_id,asset_id));
CREATE TABLE passport_entries (id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),passport_id uuid NOT NULL REFERENCES passports(id),asset_id uuid NOT NULL REFERENCES assets(id),type text NOT NULL,title text NOT NULL,occurred_at timestamptz NOT NULL,mileage integer,provider_organization_id uuid REFERENCES organizations(id),document_ids uuid[] NOT NULL DEFAULT '{}',visibility text NOT NULL CHECK(visibility IN('owner_only','shared_professionals','resale_public')),evidence_hash char(64),created_by uuid NOT NULL,created_at timestamptz NOT NULL);
CREATE INDEX passport_entries_timeline_idx ON passport_entries(tenant_id,passport_id,occurred_at DESC);
CREATE TABLE asset_deadlines (id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),passport_id uuid NOT NULL REFERENCES passports(id),asset_id uuid NOT NULL REFERENCES assets(id),type text NOT NULL,label text NOT NULL,due_at timestamptz NOT NULL,due_mileage integer,status text NOT NULL CHECK(status IN('scheduled','completed','dismissed')),source_entry_id uuid REFERENCES passport_entries(id),created_at timestamptz NOT NULL);
CREATE INDEX asset_deadlines_due_idx ON asset_deadlines(tenant_id,due_at) WHERE status='scheduled';
CREATE TABLE passport_qr_grants (id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),passport_id uuid NOT NULL REFERENCES passports(id),purpose text NOT NULL CHECK(purpose IN('owner_portal','booking','service_intake','resale_view')),token_hash char(64) NOT NULL,max_uses integer NOT NULL CHECK(max_uses>=1),use_count integer NOT NULL DEFAULT 0 CHECK(use_count>=0 AND use_count<=max_uses),expires_at timestamptz NOT NULL,revoked_at timestamptz,created_by uuid NOT NULL,created_at timestamptz NOT NULL,UNIQUE(tenant_id,token_hash));
CREATE TABLE reminders (id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),deadline_id uuid NOT NULL REFERENCES asset_deadlines(id),customer_id uuid NOT NULL REFERENCES customers(id),channel text NOT NULL CHECK(channel IN('email','sms','push')),window_days integer NOT NULL,status text NOT NULL CHECK(status IN('pending','sent','cancelled')),scheduled_for timestamptz NOT NULL,created_at timestamptz NOT NULL,UNIQUE(tenant_id,deadline_id,window_days,channel));
DO $$ DECLARE table_name text; BEGIN FOREACH table_name IN ARRAY ARRAY['passports','passport_entries','asset_deadlines','passport_qr_grants','reminders'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',table_name);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',table_name);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',table_name);END LOOP;END $$;
